mapper.select:
select flow_id, user_id, biz_type, biz_id, change_type, power_num, before_balance, after_balance, remark, create_time
from ai_c_wallet_flow

    and user_id = #{userId}
    and biz_type = #{bizType}
    and change_type = #{changeType}

order by flow_id desc

select count(1)
from ai_c_wallet_flow
where biz_type = #{param1}
  and biz_id = #{param2}
  and change_type = #{param3}
